import { createSignal, onMount, Show, For } from 'solid-js';
import { WidgetsApi, Configuration } from '@/api';
import type {
    ResponsesGithubWidgetData,
    ResponsesGithubWidgetCommitsWeekData,
    ResponsesGithubWidgetCommitsDayData,
} from '@/api/models';

interface GitHubProfileWidgetProps {
    widgetId: string;
    authToken: string;
    variant?: 'sm' | 'lg' | 'wide';
    showStats?: boolean;
}

export default function GitHubProfileWidget(props: GitHubProfileWidgetProps) {
    const [data, setData] = createSignal<ResponsesGithubWidgetData | null>(null);
    const [loading, setLoading] = createSignal(true);
    const [error, setError] = createSignal<string | null>(null);

    const variant = () => props.variant || 'lg';
    const showStats = () => props.showStats ?? true;

    onMount(async () => {
        try {
            const config = new Configuration({
                basePath: '/api',
            });
            const api = new WidgetsApi(config);

            const response = await api.getGithubWidgetData({
                authorization: `Bearer ${props.authToken}`,
                userWidgetId: props.widgetId,
            });

            if (response.success && response.data) {
                setData(response.data);
            } else {
                throw new Error(response.message || 'Failed to fetch GitHub widget data');
            }
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to fetch data');
        } finally {
            setLoading(false);
        }
    });

    const handleClick = () => {
        const profile = data()?.profile;
        if (profile?.htmlUrl) {
            window.open(profile.htmlUrl, '_blank');
        }
    };

    // Helper to get day data from a week
    const getDaysFromWeek = (week: ResponsesGithubWidgetCommitsWeekData): ResponsesGithubWidgetCommitsDayData[] => {
        return [
            week.monday,
            week.tuesday,
            week.wednesday,
            week.thursday,
            week.friday,
            week.saturday,
            week.sunday,
        ].filter((day): day is ResponsesGithubWidgetCommitsDayData => day !== undefined);
    };

    // Commit Graph Component
    const CommitGraph = () => {
        const weeks = () => data()?.commits?.weeks || [];
        const total = () => data()?.commits?.total || 0;

        return (
            <div class="w-full mt-3">
                <div class="flex items-center justify-between mb-2">
                    <span class="text-xs text-gray-400">
                        {total()} commits
                    </span>
                    <div class="flex items-center gap-1 text-xs text-gray-500">
                        <span>Less</span>
                        <div class="w-2 h-2 rounded-sm" style={{ "background-color": "#cc1e1e" }} />
                        <div class="w-2 h-2 rounded-sm" style={{ "background-color": "#9c1e5e" }} />
                        <div class="w-2 h-2 rounded-sm" style={{ "background-color": "#6c1e9e" }} />
                        <div class="w-2 h-2 rounded-sm" style={{ "background-color": "#3c1ede" }} />
                        <div class="w-2 h-2 rounded-sm" style={{ "background-color": "#1e1efc" }} />
                        <span>More</span>
                    </div>
                </div>
                <div class="flex gap-0.5 overflow-x-auto pb-1">
                    <For each={weeks()}>
                        {(week) => (
                            <div class="flex flex-col gap-0.5">
                                <For each={getDaysFromWeek(week)}>
                                    {(day) => (
                                        <div
                                            class="w-2.5 h-2.5 rounded-sm cursor-pointer transition-transform hover:scale-125"
                                            style={{ "background-color": day.color || "#cc1e1e" }}
                                            title={`${day.date}: ${day.count || 0} commits`}
                                        />
                                    )}
                                </For>
                            </div>
                        )}
                    </For>
                </div>
            </div>
        );
    };

    // Small variant: Avatar + Name only (minimal)
    const SmallVariant = () => (
        <div
            onClick={handleClick}
            class="h-full w-full flex flex-col items-center justify-center p-2 bg-gradient-to-br from-gray-800 to-gray-900 rounded-lg text-white cursor-pointer"
        >
            <img
                src={data()?.profile?.avatarUrl}
                alt={data()?.profile?.name}
                class="w-16 h-16 rounded-full border-2 border-primary mb-2"
            />
            <h3 class="text-sm font-bold text-center truncate w-full">
                {data()?.profile?.name}
            </h3>
            <p class="text-xs text-gray-400">GitHub</p>
        </div>
    );

    // Large variant: Full stats, details, and commit graph (vertical)
    const LargeVariant = () => (
        <div class="h-full w-full flex flex-col items-center p-4 bg-gradient-to-br from-gray-800 to-gray-900 rounded-lg text-white">
            <div onClick={handleClick} class="flex flex-col items-center cursor-pointer">
                <img
                    src={data()?.profile?.avatarUrl}
                    alt={data()?.profile?.name}
                    class="w-20 h-20 rounded-full border-2 border-primary mb-3"
                />
                <h3 class="text-lg font-bold text-center">{data()?.profile?.name}</h3>
                <Show when={data()?.profile?.company}>
                    <p class="text-xs text-gray-400">{data()?.profile?.company}</p>
                </Show>
            </div>

            <Show when={data()?.profile?.bio}>
                <p class="text-xs text-gray-300 text-center mt-2 mb-3 line-clamp-2">
                    {data()?.profile?.bio}
                </p>
            </Show>

            <Show when={showStats()}>
                <div class="w-full grid grid-cols-2 gap-2 mt-2">
                    <div class="bg-black/20 rounded p-2 text-center">
                        <div class="text-lg font-bold text-primary">
                            {data()?.profile?.followers}
                        </div>
                        <div class="text-xs text-gray-400">Followers</div>
                    </div>
                    <div class="bg-black/20 rounded p-2 text-center">
                        <div class="text-lg font-bold text-green-400">
                            {data()?.profile?.publicRepos}
                        </div>
                        <div class="text-xs text-gray-400">Repos</div>
                    </div>
                </div>
            </Show>

            <CommitGraph />
        </div>
    );

    // Wide variant: Horizontal layout with commit graph
    const WideVariant = () => (
        <div class="h-full w-full flex flex-col p-3 bg-gradient-to-r from-gray-800 to-gray-900 rounded-lg text-white">
            <div class="flex flex-row items-center gap-4">
                <img
                    src={data()?.profile?.avatarUrl}
                    alt={data()?.profile?.name}
                    class="w-16 h-16 rounded-full border-2 border-primary flex-shrink-0 cursor-pointer"
                    onClick={handleClick}
                />

                <div class="flex-1 min-w-0">
                    <h3
                        class="text-base font-bold truncate cursor-pointer hover:text-primary"
                        onClick={handleClick}
                    >
                        {data()?.profile?.name}
                    </h3>
                    <Show when={data()?.profile?.company}>
                        <p class="text-xs text-gray-400">{data()?.profile?.company}</p>
                    </Show>
                    <Show when={data()?.profile?.bio}>
                        <p class="text-xs text-gray-300 line-clamp-1 mt-1">
                            {data()?.profile?.bio}
                        </p>
                    </Show>
                </div>

                <Show when={showStats()}>
                    <div class="flex gap-3 flex-shrink-0">
                        <div class="text-center">
                            <div class="text-sm font-bold text-primary">
                                {data()?.profile?.followers}
                            </div>
                            <div class="text-xs text-gray-400">Followers</div>
                        </div>
                        <div class="text-center">
                            <div class="text-sm font-bold text-green-400">
                                {data()?.profile?.publicRepos}
                            </div>
                            <div class="text-xs text-gray-400">Repos</div>
                        </div>
                    </div>
                </Show>
            </div>

            <CommitGraph />
        </div>
    );

    return (
        <Show
            when={!loading()}
            fallback={
                <div class="h-full w-full flex items-center justify-center bg-gray-800/50 rounded-lg text-white">
                    <div class="text-sm">Loading...</div>
                </div>
            }
        >
            <Show
                when={!error() && data()}
                fallback={
                    <div class="h-full w-full flex flex-col items-center justify-center bg-red-900/20 rounded-lg text-white p-4">
                        <div class="text-3xl mb-2">&#9888;</div>
                        <div class="text-sm text-red-300">Error: {error()}</div>
                    </div>
                }
            >
                <Show when={variant() === 'sm'}>
                    <SmallVariant />
                </Show>
                <Show when={variant() === 'lg'}>
                    <LargeVariant />
                </Show>
                <Show when={variant() === 'wide'}>
                    <WideVariant />
                </Show>
            </Show>
        </Show>
    );
}
